const body = $input.item.json.body;
const productUuid = body.product?.uuid || '';
const rawBlobId   = body.product?.asset?.assetBlobId || '';
const blobUuid    = rawBlobId.replace(/\.[^.]+$/, ''); // strip extension
const orgUuid     = body.organization?.uuid || '';
const clientUuid  = body.client?.uuid || '';
const productName = body.product?.name || 'Showroom Config';
if (!rawBlobId)  throw new Error('No assetBlobId in webhook payload');
if (!orgUuid)    throw new Error('No organization.uuid in webhook payload');
if (!clientUuid) throw new Error('No client.uuid in webhook payload');
return [{ json: { productUuid, blobUuid, orgUuid, clientUuid, productName } }];

const xlsx = require('xlsx');

const binaryProp = $input.item.binary?.data;
if (!binaryProp) throw new Error('No binary data from download — check the download URL');

const buffer = Buffer.from(binaryProp.data, 'base64');
const wb = xlsx.read(buffer, { type: 'buffer' });

if (!wb.SheetNames.includes('Assets'))  throw new Error('Excel file is missing an Assets tab');
if (!wb.SheetNames.includes('Groups'))  throw new Error('Excel file is missing a Groups tab');
if (!wb.SheetNames.includes('Styling')) throw new Error('Excel file is missing a Styling tab');

// Assets tab
const assetsRaw = xlsx.utils.sheet_to_json(wb.Sheets['Assets'], { header: 1 });
const assets = assetsRaw.slice(1).filter(r => r[0]).map(r => ({
  uuid:  String(r[0] || '').trim(),
  name:  String(r[1] || '').trim(),
  group: r[3] != null ? String(r[3]).trim() : '',
  order: r[4] != null ? Number(r[4]) : null,
  qty:   r[5] != null ? Number(r[5]) : 0
}));

// Groups tab
const groupsRaw = xlsx.utils.sheet_to_json(wb.Sheets['Groups'], { header: 1 });
const groups = groupsRaw.slice(1)
  .filter(r => r[0] != null && String(r[0]).trim() !== '')
  .map(r => ({
    title:         String(r[0]).trim(),
    dividerTop:    String(r[1] || '').toLowerCase() === 'yes',
    dividerBottom: String(r[2] || '').toLowerCase() === 'yes',
    visible:       String(r[3] || 'yes').toLowerCase() !== 'no'
  }));

// Styling tab
const stylingRaw = xlsx.utils.sheet_to_json(wb.Sheets['Styling'], { header: 1 });
const stylingMap = {};
stylingRaw.slice(1).forEach(r => {
  if (r[0] && !String(r[0]).startsWith('\u2014')) {
    stylingMap[String(r[0]).trim()] = r[1] != null ? String(r[1]).trim() : '';
  }
});

return [{ json: { assets, groups, stylingMap } }];

const { assets, groups, stylingMap } = $input.item.json;
const errors = [];

// Validate
if (assets.length === 0) errors.push('Assets tab has no rows');
const groupTitles = new Set(groups.map(g => g.title));
assets.forEach(a => {
  if (!a.uuid) errors.push(`Row for "${a.name}" has no UUID`);
  if (a.group && !groupTitles.has(a.group)) {
    errors.push(`Asset "${a.name}" references group "${a.group}" not found in Groups tab`);
  }
});

// Build groups for API
const apiGroups = groups.map(g => {
  const dividers = [];
  if (g.dividerTop)    dividers.push('TOP');
  if (g.dividerBottom) dividers.push('BOTTOM');
  const productsInfo = assets
    .filter(a => a.group === g.title)
    .sort((a, b) => (a.order ?? 999) - (b.order ?? 999))
    .map((a, idx) => ({ productUuid: a.uuid, order: a.order ?? idx + 1, visible: true }));
  return { title: g.title, dividers, visible: g.visible, productsInfo };
});

// Build layout attributes
const layout = {};
if (stylingMap['Background Color']) layout.BACKGROUND_COLOR = stylingMap['Background Color'];
if (stylingMap['Text Color'])       layout.TEXT_COLOR        = stylingMap['Text Color'];
if (stylingMap['Divider Color'])    layout.DIVIDER_COLOR     = stylingMap['Divider Color'];
if (stylingMap['Products Per Row']) layout.PRODUCTS_PER_ROW  = parseInt(stylingMap['Products Per Row'], 10);
if (stylingMap['Image Style'])      layout.IMAGE_STYLE       = String(stylingMap['Image Style']).toUpperCase();

const showroomName   = stylingMap['Showroom Name'] || 'New Showroom';
const productsUuids  = assets.map(a => a.uuid).filter(Boolean);

return [{ json: { productsUuids, apiGroups, layout, showroomName, errors } }];

const built   = $('Build Payload').first().json;
const context = $('Extract Context').first().json;
const resp    = $input.item.json;

const newUuid = resp.response?.uuid || null;
const success = resp.success === true && !!newUuid;

const lines = [
  'VNTANA Showroom Maker — Processing Log',
  '======================================',
  `Source file:    ${context.productName}`,
  `Showroom name:  ${built.showroomName}`,
  `Status:         ${success ? 'SUCCESS' : 'ERROR'}`,
];
if (newUuid)                  lines.push(`New showroom UUID: ${newUuid}`);
if (resp.errors?.length)      lines.push(`API errors: ${resp.errors.join(', ')}`);
if (built.errors?.length) {
  lines.push('');
  lines.push('Validation warnings:');
  built.errors.forEach(e => lines.push(`  - ${e}`));
}
lines.push('');
lines.push(`Assets:  ${built.productsUuids.length}`);
lines.push(`Groups:  ${built.apiGroups.length}`);

return [{ json: { logText: lines.join('\n'), success, newShowroomUuid: newUuid } }];
